export default function UsageStreakCard({
  currentStreak,
  longestStreak,
  freezeAvailable,
  freezeDaysUntilReload,
  recentDays,
  isLoading,
  error,
  style,
}: UsageStreakCardProps) {
  const { theme, themeMode } = useTheme();
  const widgetStreakCardFollowTheme = useSettingsStore(
    (state) => state.widgetStreakCardFollowTheme
  );
  const widgetStreakCardGradientStart = useSettingsStore(
    (state) => state.widgetStreakCardGradientStart
  );
  const widgetStreakCardGradientMiddle = useSettingsStore(
    (state) => state.widgetStreakCardGradientMiddle
  );
  const widgetStreakCardGradientEnd = useSettingsStore(
    (state) => state.widgetStreakCardGradientEnd
  );
  const gradientColors =
    !widgetStreakCardFollowTheme
      ? ([
          normalizeWidgetCardColor(
            widgetStreakCardGradientStart,
            DEFAULT_WIDGET_CARD_STYLE_COLORS.widgetStreakCardGradientStart
          ),
          normalizeWidgetCardColor(
            widgetStreakCardGradientMiddle,
            DEFAULT_WIDGET_CARD_STYLE_COLORS.widgetStreakCardGradientMiddle
          ),
          normalizeWidgetCardColor(
            widgetStreakCardGradientEnd,
            DEFAULT_WIDGET_CARD_STYLE_COLORS.widgetStreakCardGradientEnd
          ),
        ] as const)
      : themeMode === "sepia"
        ? ([
            "#a4551f",
            "#c1642d",
            "#8f4724",
          ] as const)
        : themeMode === "midnight"
          ? (["#1b0a06", "#3b160f", "#5a2116"] as const)
          : theme.isDark
            ? (["#2D0F0A", "#562016", "#8A2E19"] as const)
            : (["#FF7A18", "#FF5A3D", "#FF3F6C"] as const);
  const mainTextColor = getReadableTextColor(gradientColors[1]);
  const secondaryTextColor = withAlpha(mainTextColor, 0.9);
  const mutedTextColor = withAlpha(mainTextColor, 0.8);
  const freezeText = error
    ? "Freeze status unavailable"
    : freezeAvailable
      ? "Freeze ready"
      : `Freeze reload: ${freezeDaysUntilReload}d`;
  const visibleStreakDayNumbers = React.useMemo(
    () => getVisibleStreakDayNumbers(recentDays, currentStreak),
    [recentDays, currentStreak],
  );

  return (
    <LinearGradient
      colors={gradientColors}
      start={{ x: 0, y: 0 }}
      end={{ x: 1, y: 1 }}
      style={[styles.card, { borderColor: theme.border }, style]}
    >
      <View style={styles.glowLarge} />
      <View style={styles.glowSmall} />

      <View style={styles.headerRow}>
        <View style={styles.titleWrap}>
          <Ionicons name="flame" size={18} color="#FFD166" />
          <Text style={[styles.title, { color: mainTextColor }]}>App Streak</Text>
        </View>
        <View style={[styles.bestBadge, { backgroundColor: withAlpha(mainTextColor, 0.2) }]}>
          <Text style={[styles.bestBadgeText, { color: mainTextColor }]}>
            Best {longestStreak}
          </Text>
        </View>
      </View>

      <View style={styles.mainRow}>
        {isLoading ? (
          <View style={styles.loadingRow}>
            <ActivityIndicator color={mainTextColor} />
            <Text style={[styles.loadingText, { color: secondaryTextColor }]}>
              Updating...
            </Text>
          </View>
        ) : (
          <>
            <Text style={[styles.streakNumber, { color: mainTextColor }]}>
              {currentStreak}
            </Text>
            <Text style={[styles.streakUnit, { color: secondaryTextColor }]}>日</Text>
          </>
        )}
      </View>

      <View style={styles.freezeRow}>
        <Ionicons name="snow-outline" size={14} color={secondaryTextColor} />
        <Text style={[styles.freezeText, { color: secondaryTextColor }]}>
          {freezeText}
        </Text>
      </View>

      <View style={[styles.weekRow, { borderTopColor: withAlpha(mainTextColor, 0.2) }]}>
        {recentDays.map((day, index) => {
          const streakDayNumber = visibleStreakDayNumbers[index];
          const milestoneVariant = getMilestoneVariant(streakDayNumber);

          return (
            <View key={day.dayKey} style={styles.dayItem}>
              <View
                style={[
                  styles.dayIconContainer,
                  day.active
                    ? [styles.dayIconContainerActive, { backgroundColor: withAlpha(mainTextColor, 0.2) }]
                    : [styles.dayIconContainerInactive, { backgroundColor: withAlpha(mainTextColor, 0.12) }],
                ]}
              >
                <StreakDayStatusIcon active={day.active} milestoneVariant={milestoneVariant} />
              </View>
              <Text
                style={[
                  styles.dayLabel,
                  { color: mutedTextColor },
                  day.isToday && [styles.dayLabelToday, { color: mainTextColor }],
                ]}
              >
                {day.label}
              </Text>
            </View>
          );
        })}
      </View>
    </LinearGradient>
  );
}

